import "../shared/index.tsp";

namespace MyDomain;

@friendlyName("MyResource")
model MyResource {
  ...Shared.ResourceWithKey;

  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  @summary("Status")
  status: MyStatus;
}

interface MyResourceOperations {
  @post
  @operationId("create-my-resource")
  create(@body body: Shared.CreateRequest<MyResource>): Shared.CreateResponse<MyResource> | Common.ErrorResponses;

  @get
  @operationId("list-my-resources")
  list(...Common.PagePaginationQuery): Shared.PagePaginatedResponse<MyResource> | Common.ErrorResponses;
}

// In operations.tsp, inside interface SubscriptionsOperations:
@post
@operationId("pause-subscription")
@summary("Pause subscription")
@route("/{subscriptionId}/pause")
pause(
  @path subscriptionId: Shared.ULID,
  @body body: SubscriptionPause,
):
  | Shared.UpdateResponse<Subscription>
  | Common.NotFound
  | Common.Conflict
  | Common.ErrorResponses;

// In subscription.tsp:
@friendlyName("BillingSubscriptionPause")
model SubscriptionPause {
  timing?: SubscriptionEditTiming = SubscriptionEditTimingEnum.Immediate;
}
